CREATE TABLE `fact_layoffs` (
  `Id_Layoff` int NOT NULL AUTO_INCREMENT,
  `Company` varchar(255) NOT NULL,
  `Total_Laid_Off` int NOT NULL,
  `Date` date NOT NULL,
