  `Id_Sector` int NOT NULL,
  `Id_Region` int NOT NULL,
  PRIMARY KEY (`Id_Layoff`),
  KEY `FK_Layoffs_Sector` (`Id_Sector`),
  KEY `FK_Layoffs_Region` (`Id_Region`),
  CONSTRAINT `FK_Layoffs_Region` FOREIGN KEY (`Id_Region`) REFERENCES `dim_region` (`Id_Region`),
  CONSTRAINT `FK_Layoffs_Sector` FOREIGN KEY (`Id_Sector`) REFERENCES `dim_sector` (`Id_Sector`)
) ENGINE=InnoDB AUTO_INCREMENT=1024 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
